# Category: business_logic_flaw

class CheckoutProcess:
    def __init__(self, cart, user):
        self.cart = cart
        self.user = user

    def validate_cart(self):
        for item in self.cart:
            if item['quantity'] <= 0:
                return False
        return True

    def apply_discount(self, code):
        if code in self.user['permissions']:
            for item in self.cart:
                item['price'] -= item['price'] * code['discount']
        else:
            raise Exception("User does not have permission to use this code")

    def calculate_tax(self):
        for item in self.cart:
            item['price'] += item['price'] * 0.07  # assuming a 7% tax rate

    def process_payment(self, payment_info):
        total = sum(item['price'] for item in self.cart)
        if payment_info['balance'] < total:
            raise Exception("Insufficient funds")
        payment_info['balance'] -= total

    def create_order(self):
        order = {
            'user': self.user,
            'cart': self.cart,
            'total': sum(item['price'] for item in self.cart)
        }
        return order

    def checkout(self, discount_code, payment_info):
        if not self.validate_cart():
            raise Exception("Invalid cart")
        self.apply_discount(discount_code)
        self.calculate_tax()
        self.process_payment(payment_info)
        return self.create_order()